(25, 'CWMSR', 'admin@cwmsrfupre.com.ng', 'imeldablankson4u@gmail.com', 'Document upload', 'Good morning,\r\nKindly upload your document O\'level results and Postgraduate certificate/transcript within the next 3 days or you forfeit your admission. \r\nAlternatively, you can send the document through our email (wmsr@fupre.edu.ng) if there are challenges with website upload.\r\n\r\nRegards,\r\n\r\nIbuwa Ogundimu\r\nHead, Admission team office', 0, 'inbox', NULL, '2025-10-27 12:58:24', 'wmsr@fupre.edu.ng'),
(26, 'CWMSR', 'admin@cwmsrfupre.com.ng', 'imeldablankson4u@gmail.com', 'Document Upload', 'Good morning,\r\nKindly upload your document O\'level results and Postgraduate certificate/transcript within the next 3 days or you forfeit your admission.\r\nAlternatively, you can send the document through our email (wmsr@fupre.edu.ng) if there are challenges with website upload.\r\n\r\nRegards,\r\n\r\nIbuwa Ogundimu\r\nHead, Admission team office', 0, 'inbox', NULL, '2025-10-28 11:55:07', ''),
(27, 'CWMSR', 'admin@cwmsrfupre.com.ng', 'christiansoft950@cwmsrfupre.com.ng', 'Congratulations on Your Admission to the Masterâ€™s Programme â€“ FUPRE Centre for Waste Management and Sustainable Resources', 'Dear Lawrence Chinonso Christian,\r\n\r\nWarm greetings from the Centre for Waste Management and Sustainable Resources,\r\nFederal University of Petroleum Resources, Effurun (FUPRE).\r\n\r\nWe are pleased to inform you that you have been offered provisional admission into the Masterâ€™s Programme of the Centre for the 2025/2026 Academic Session.\r\n\r\nAttached is your official admission letter, which provides detailed information about your financial commitments and next steps for registration. Kindly review it thoroughly and follow the given instructions.\r\n\r\nPlease take note of the following payment details:\r\n\r\nTotal Payable Fees: â‚¦535,000 (Acceptance, Administrative, Examination, and School Fees inclusive)\r\n\r\nAccount Name: Centre for Waste Management and Sustainable Resources\r\n\r\nAccount Number: 1310206641\r\n\r\nBank: Zenith Bank\r\n\r\nAfter making the payment, send your proof of payment (clearly stating your full name and programme) to wmsr@fupre.edu.ng for verification.\r\n\r\nYou are required to pay your acceptance fee within two (2) weeks of this notification to secure your admission. Failure to do so will result in forfeiture of your slot.\r\n\r\nCongratulations once again on your admission. We look forward to supporting your growth and success throughout your postgraduate journey.\r\nWarm regards,\r\n\r\nMr Ibuwa Ogundimu\r\nHead, Admissions office, \r\nCentre for Waste Management and Sustainable Resources, \r\nFederal University of Petroleum Resources\r\nEffurun, Delta State, Nigeria.', 1, 'inbox', '[\"1761657031_Lawrence_Chinonso_Christian-MS_Petroleum.doc\"]', '2025-10-28 13:10:46', 'christiansoft950@gmail.com'),
