(66, 'CWMSR', 'admin@cwmsrfupre.com.ng', 'sylvesterdavis49@gmail.com', 'Upload of transcript and certificate- treat as uregent', 'Der Imafidon Sylvester Esemu,\r\n\r\nPlease, you need to upload your SSCE/WAEC results before we can grant you admission.\r\n\r\nRegards,\r\n\r\nDr Akinyemi Ogunkeyede\r\nCentre Director', 0, 'inbox', NULL, '2026-03-01 02:43:27', 'wmsr@fupre.edu.ng'),
(67, 'CWMSR', 'admin@cwmsrfupre.com.ng', 'sylvesterdavis49@gmail.com', 'upload of certificate and transcript-urgent', 'Good day, \r\nPlease upload your O\'level certificate, B.Sc./M.Sc. certificates and transcripts.\r\n\r\nRegards\r\nDr Akinyemi ogunkeyede\r\nCentre Director', 0, 'inbox', NULL, '2026-03-01 02:49:08', ''),
(68, 'CWMSR', 'admin@cwmsrfupre.com.ng', 'benedicta.utulu@gmail.com', 'Upload of documents', 'Dear, Benedicta,\r\nPlease your admission is a temporary admission till the centre receives the upload O\'level certificate and your B.Sc. transcripts.\r\nRegards,\r\n\r\nDr Akinyemi Ogunkeyede\r\nCentre Director', 1, 'inbox', NULL, '2026-03-01 02:53:23', 'benedicta.utulu@cwmsrfupre.com.ng'),
