INSERT INTO `lecture_notes` (`id`, `course_id`, `lecturer_id`, `title`, `description`, `file_path`, `created_at`) VALUES
(14, 96, 30, 'ESW 812- Community Engagement and Participatory Development', 'This Lecture note is for master\'s students', '', '2025-11-09 01:35:28'),
(15, 109, 37, 'Principle of epidemiology in public health ', 'Detailed note on the subject matter', 'uploads/lecture_notes/note_691645aa695561.88591334.pdf', '2025-11-13 20:55:06'),
(16, 81, 38, 'Lecture 1', 'This lecture gives the definition and classification of waste based on the nature as solid, liquid and gaseous waste. \r\n\r\nAlso, it gives explaination of municipal solid waste, source and type based classification of solid waste.\r\n', 'uploads/lecture_notes/note_6918b8ece78f28.37210111.pdf', '2025-11-15 17:31:24'),
(17, 82, 22, 'Waste Collection', 'Lecture Note For Week 1&2', 'uploads/lecture_notes/note_691a2af03d1918.78358101.docx', '2025-11-16 19:50:08'),
(18, 108, 17, 'Introduction to prinsiples of Environmental health', 'The notes will comprise an overview of the fundamental concepts and principles in environmental health. It will focus on the environmental factors that affect human health and quality of life and biologicla, chemical and physical hazards in the environment.  ', 'uploads/lecture_notes/note_691af3f6756e45.74559296.docx', '2025-11-17 10:07:52'),
(19, 80, 11, 'Introduction and Overview of Waste Management', 'Define & Classify Waste, Explain Waste Hierarchy, Describe Historical Development, Relate to Sustainability, \r\n\r\n', 'uploads/lecture_notes/note_691b446ef21560.92753835.pdf', '2025-11-17 15:51:12'),
(20, 111, 11, 'Intodcution to Environmental policy and regulation', 'This lecture introduces the foundations of environmental policy, major policy instruments, and the regulatory frameworks in Nigeria, across Africa, and globally. It focuses on institutional structures, legal frameworks, compliance mechanisms, and emerging issues shaping modern environmental governance.', 'uploads/lecture_notes/note_691c9b495f32d1.21183464.doc', '2025-11-18 16:14:01'),
(23, 112, 31, 'Health Impact Assesssment', 'Importance of Health Impact Assessment', 'uploads/lecture_notes/note_6925e9d0296480.83439859.docx', '2025-11-25 17:39:28'),
(22, 65, 39, 'Lecture Note 1', 'This lecture note tries to define waste management to give a base for the introduction of petroleum waste and the management of petroleum waste.\r\nThe highlights of this note include the following topics:\r\nTypes of waste\r\nEnvironmental Impact of Petroleum Waste\r\nWaste Management Principles and Hierarchy\r\nPetroleum Waste Treatment Techniques\r\nSpill Prevention and Control\r\nRegulatory Framework\r\nEmerging Trends in Petroleum Waste Management\r\n', 'uploads/lecture_notes/note_6925751c3cece7.29478928.docx', '2025-11-25 09:21:32'),
(24, 97, 30, 'LECTURE NOTE ESW 813', 'This lecture is for Masters students on Environmental Justices on Human rights ', 'uploads/lecture_notes/note_6926fb0e702e38.91980888.mht', '2025-11-26 13:05:18'),
(25, 127, 15, 'PWM 833 Lecture Note', 'Below is the course content for PWM833: Introduction to Artificial Intelligence and Machine Learning in environmental systems, Big Data analytics for waste generation, transportation, and treatment optimisation, Predictive modelling and simulation for pollution forecasting, IoT-enabled waste monitoring systems and smart sensor applications, AI-driven decision support systems for waste management planning, Integration of AI in Environmental Impact Assessment (EIA) and lifecycle analysis (LCA) Case studies: AI-enabled smart cities and waste sorting automation, Ethics, transparency, and governance in AI for environmental management, Software tools: Python, TensorFlow, MATLAB, and RapidMiner', 'uploads/lecture_notes/note_69313ec86aeef0.05576745.docx', '2025-12-04 07:56:56'),
(26, 108, 17, 'Soil, air and water as environments', 'Different types of pollution of the environment to include soil, air, water and build-in environment ', 'uploads/lecture_notes/note_69371b4a592ef0.00720222.docx', '2025-12-08 18:39:06'),
(30, 122, 19, '818 GENERAL', 'Environmental politics from Dr.Beatrice', 'uploads/lecture_notes/note_694d3b6b529100.09422677.docx', '2025-12-25 13:26:03'),
(28, 65, 43, 'Lecture note 1', 'Lecture note 1', 'uploads/lecture_notes/note_694565f4275103.08873639.pdf', '2025-12-19 14:49:24'),
(29, 65, 43, 'Slide for an overview of the lecture', 'Slides', 'uploads/lecture_notes/note_694922a9c578d0.79043438.pptx', '2025-12-22 10:51:29'),
(31, 125, 19, '818General', 'Environmental politics and governance ', 'uploads/lecture_notes/note_694d3bd8a524a3.42692366.docx', '2025-12-25 13:27:52'),
(32, 65, 43, 'Drilling cutting management and treatment ', 'Drilling cutting management and treatment ', 'uploads/lecture_notes/note_69502d9f1a5160.82956835.pdf', '2025-12-27 19:04:00'),
(33, 65, 43, 'Produce water management and treatment', 'Produce water management and treatment', 'uploads/lecture_notes/note_69502dfd27d212.83842004.pdf', '2025-12-27 19:05:38'),
(34, 65, 43, 'Produce water management and treatment', 'Produce water management and treatment', 'uploads/lecture_notes/note_69502e045b0517.68505848.pdf', '2025-12-27 19:05:43'),
(35, 65, 43, 'Oil sludge management and treatment', 'Oil sludge management and treatment', 'uploads/lecture_notes/note_69502e6cb273c7.99137385.pdf', '2025-12-27 19:07:27'),
(36, 83, 12, 'Lecture note 2', 'Treatment methods of household organic wastes via mechanical, chemical, thermal and biological approaches. ', 'uploads/lecture_notes/note_695d1cf1153871.81200008.docx', '2026-01-06 14:32:17'),
(37, 70, 11, 'Spill response strategies', 'strategies used for response to spill of oil', 'uploads/lecture_notes/note_69693b793066d3.66567159.pdf', '2026-01-15 19:09:45'),
(38, 127, 15, 'Week 1 & 2 lecture notes', 'Detailed note for week 1 and 2 lecture', 'uploads/lecture_notes/note_697ce290a35c07.80796139.pdf', '2026-01-30 16:55:44'),
(39, 126, 15, 'Week 1 & 2 lecture notes', 'Detailed note for week 1 and 2', '', '2026-01-30 16:56:27'),
(40, 81, 38, 'Lecture 1', 'WASTE - TYPES AND CLASSIFICATION \r\n', 'uploads/lecture_notes/note_69817077504b78.54154796.pptx', '2026-02-03 03:50:15'),
(41, 81, 38, 'Lecture 2', 'Waste Sources and Generation Rates', 'uploads/lecture_notes/note_6981714bb1f121.05359007.pptx', '2026-02-03 03:53:47'),
(42, 81, 38, 'Lecture 3', 'Factors Influencing Waste Generation', 'uploads/lecture_notes/note_698171a6b3dc26.12249487.pptx', '2026-02-03 03:55:18'),
(43, 68, 11, ' EIA report architecture', 'A comprehensive lecture guide for graduate students and early-career environmental professionals on the structure, purpose, \r\nand preparation of professional EIA reports. This document walks through each section of the EIA report architecture 4 from \r\nthe cover page to the appendices 4 equipping you with the conceptual clarity and practical understanding needed to produce \r\nscientifically rigorous, legally compliant, and stakeholder-inclusive assessments.', 'uploads/lecture_notes/note_69a35fe9b2ce72.82334747.pdf', '2026-02-28 21:36:42'),
(45, 84, 11, 'EIA REPORT COMPONENT', 'EIA STRUCTURE', '', '2026-03-01 02:01:16'),
(46, 20, 11, 'Lecture note', 'Waste management in oil and gas', 'uploads/lecture_notes/note_69ad76fbdfb976.00421520.pdf', '2026-03-08 13:17:49');
