(46, 'IMELDA TAIYE, BLANKSON', 'imeldablankson4u@cwmsrfupre.com.ng', '', 'wmsr@fupre.edu.ng', 'Receipt of payment', 'Good day,\r\n\r\nI hope this email finds you well.\r\n\r\nFind attached the receipt of payment for the professional Doctoral Programme at the Centre for Waste Management and Sustainable Resources, Federal University of Petroleum Resources, Effurun, for Imelda Blankson.\r\n\r\nThank you.\r\n\r\nBest regards,\r\nImelda Blankson', '2025-11-09 06:26:08', '', '[\"1762669568_Receipt_of_payment_for_PhD_in_CWMSR_for_Imelda_Blankson.pdf\"]'),
(47, 'CWMSR', 'admin@cwmsrfupre.com.ng', 'IBUWA OGUNDIMU', 'ibuwaomoregie@yahoo.com', 'draft admission letter', 'See attached for your modification.\r\nUse the Edwin as draft to modified Masters, while Sodiq for PhD.\r\nRead through and amend anything like physical visit to the centre office. Check that a proof of payments should be send to the email.', '2025-11-09 09:16:37', '', '[\"1762679752_Centurion_Okon_Awakessien.doc\",\"1762679767_EDWIN_ANYIM.doc\",\"1762679782_Sodiq_Adedamola_Alaka-PhD.doc\"]'),
(48, 'EDWIN ANYIM', 'akachiedwin@cwmsrfupre.com.ng', 'EDWIN ANYIM', 'wmsr@fupre.edu.ng', 'PART PAYMENT FOR MSc PETROLEUM WASTE MANAGEMENT', 'I write to inform you that a sum of =N=250,000 was paid into the school zenith bank account as part payment for my Msc program. Here are my details below. Also attached below is an evidence of my payment.\r\n\r\nNAME: EDWIN ANYIM\r\nPROGRAMME: MSc petroleum waste management.', '2025-11-10 12:26:22', '', '[\"1762777582_part_payment_receipt.pdf\"]'),
