(56, 'Matilda Iwunor', 'mkiwunor@cwmsrfupre.com.ng', 'IMELDA BLANKSON', 'imeldablankson4u@cwmsrfupre.com.ng', 'Homework enquiry', 'hello\r\nHow do we submit homework and when is usually the deadline to submit them.\r\n\r\ni anticipate your response.\r\n\r\nThank you.\r\n\r\nKind regards,\r\n\r\nYour colleague', '2025-12-03 12:24:38', '', NULL),
