(62, 'Oritseweyinmi Erikowa-Orighoye', 'oritseweyinmi.erikowa-orighoye@cwmsrfupre.com.ng', 'Centurion Okon Awakessien', 'centurionawakessien@cwmsrfupre.com.ng', 'CA ESW 816', 'Hello Everyone, \r\n\r\nI hope you are doing well. \r\n\r\nI have attached a copy of your continuous assessment for ESW 816 Disaster Risk Reduction and Management.\r\n\r\nIf you have questions, please reach out to me via my WhatsApp number. \r\n\r\nWarm regards\r\nDr Weyinmi Erikowa-Orighoye', '2026-01-22 18:29:11', 'mkiwunor@cwmsrfupre.com.ng,chuksvenantius@cwmsrfupre.com.ng', '[\"1769106551_ESW_816__Continuous_Assessment__Community-Based_DRR_Action_Plan_January_2026.pdf\"]'),
(63, 'Oritseweyinmi Erikowa-Orighoye', 'oritseweyinmi.erikowa-orighoye@cwmsrfupre.com.ng', 'enaworedavid@gmail.com', 'enaworedavid@cwmsrfupre.com.ng', 'EHM 816 CA', 'Hello Mr David, \r\n\r\nI hope this email finds you well. \r\n\r\nI have attached a copy of the EHM 816 Environmental Health Laboratory Techniques CA \r\n\r\nIf you have any questions, please reach out to me via my WhatsApp Number. \r\n\r\nBest regards\r\nDr Weyinmi Erikowa-Orighoye', '2026-01-22 18:46:12', '', '[\"1769107572_EHM_816__Continuous_Assessment_Portfolio_Jan_2026.pdf\"]'),
