(68, 'CWMSR', 'admin@cwmsrfupre.com.ng', 'Imafidon Sylvester Esemu', 'sylvesterdavis49@gmail.com', 'Upload of transcript and certificate- treat as uregent', 'Der Imafidon Sylvester Esemu,\r\n\r\nPlease, you need to upload your SSCE/WAEC results before we can grant you admission.\r\n\r\nRegards,\r\n\r\nDr Akinyemi Ogunkeyede\r\nCentre Director', '2026-03-01 02:43:27', 'wmsr@fupre.edu.ng', NULL),
(69, 'CWMSR', 'admin@cwmsrfupre.com.ng', 'wmsr@fupre.edu.ng', 'sylvesterdavis49@gmail.com', 'upload of certificate and transcript-urgent', 'Good day, \r\nPlease upload your O\'level certificate, B.Sc./M.Sc. certificates and transcripts.\r\n\r\nRegards\r\nDr Akinyemi ogunkeyede\r\nCentre Director', '2026-03-01 02:49:08', '', NULL),
(70, 'CWMSR', 'admin@cwmsrfupre.com.ng', '', 'benedicta.utulu@gmail.com', 'Upload of documents', 'Dear, Benedicta,\r\nPlease your admission is a temporary admission till the centre receives the upload O\'level certificate and your B.Sc. transcripts.\r\nRegards,\r\n\r\nDr Akinyemi Ogunkeyede\r\nCentre Director', '2026-03-01 02:53:23', 'benedicta.utulu@cwmsrfupre.com.ng', NULL),
(71, '', 'benedicta.utulu@cwmsrfupre.com.ng', 'CWMSR', 'admin@cwmsrfupre.com.ng', 'Re: Upload of documents', '--- Original Message ---\r\n\r\n\r\n--- Original Message ---\r\nFrom: CWMSR <admin@cwmsrfupre.com.ng>\r\nSent: 2026-03-01 03:53:23\r\nSubject: Upload of documents\r\n\r\nDear, Benedicta,\r\nPlease your admission is a temporary admission till the centre receives the upload O\'level certificate and your B.Sc. transcripts.\r\nRegards,\r\n\r\nDr Akinyemi Ogunkeyede\r\nCentre Director', '2026-03-01 18:32:49', '', '[\"1772389969_NECO_CERTIFICATE.pdf\"]'),
(72, 'Matilda Iwunor', 'mkiwunor@cwmsrfupre.com.ng', 'Nduagu Ozioma Israel', 'nduagu.ozioma.israel@cwmsrfupre.com.ng', 'Update on ESW 811', 'Good Afternoon Sir,\r\n\r\nI hope this email finds you well.\r\n\r\nI am one of the 3 ESW PhD students.\r\n\r\nThe Director asked me to contact you regarding ESW 811 as it is a compulsory course and the examination must be met with success.\r\n\r\nI anticipate your response.\r\n\r\nThank you.\r\n\r\nKind regards,\r\n\r\nIWUNOR MATILDA. K.', '2026-03-03 14:26:44', 'mkiwunor@gmail.com', NULL);
