(21, 'Lemuel Ossai Ifuwe', 'lemuelossaiifuwe@gmail.com', 'lemuelossaiifuwe@gmail.com', '07035495169', '3b Nigercat link road off refinery road ekpan', '1', 'test', 'testtest', 'test', 'uploads/students_applications/app_file_68a4c8846e6691.99585037.pdf', '$2y$10$eRNLf/KphpT25DvGMvTtVu3cTtPOrky.HQgE.j4SUixv.4uFnsr6G', '', 0.00, 'uploads/proof_of_payments/payment_proof_68a4c8846e7543.50657410.jpg', 'admitted', 'suspended', 'RFU/2025/4003', '2025-08-19 18:55:00', '{\"level_id\": 1, \"semester_id\": 1}', '[\n  {\"level_id\":1,\"semester_id\":1},\n  {\"level_id\":1,\"semester_id\":2},\n  {\"level_id\":2,\"semester_id\":1},\n  {\"level_id\":2,\"semester_id\":2},\n  {\"level_id\":3,\"semester_id\":1},\n  {\"level_id\":3,\"semester_id\":2},\n  {\"level_id\":4,\"semester_id\":1},\n  {\"level_id\":4,\"semester_id\":2},\n  {\"level_id\":5,\"semester_id\":1},\n  {\"level_id\":5,\"semester_id\":2}\n]', 'current'),
(31, 'Itse osan', 'itse.osan@cwmsrfupre.com.ng', 'itse.osan@cwmsrfupre.com.ng', '08038526854', '10 Diden Street', '2', 'Bsc botany', 'Ministry of environment 2006 - till date', 'I want to improve my knowledge on waste management and environmental research on recycling and renewable waste management ', 'uploads/students_applications/app_file_68cd3f06481800.12475453.pdf', '$2y$10$CzT8Au8GEFMsLvwrquMakO9KMnok5QuyaJn/zoipZ.jajjz7Zl/Te', '', 0.00, 'uploads/proof_of_payments/payment_proof_68cd3f064f29f5.14458468.jpg', 'applied', 'not suspended', NULL, '2025-09-19 11:31:18', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(36, 'Lawrence Chinonso Christian', 'christiansoft950@cwmsrfupre.com.ng', 'christiansoft950@gmail.com', '08058112646', 'Ovie Layout, Agbarho.', '5', 'Bachelor of Technology (B.Tech)', 'Project Engineer at Nestoil Limited (August 2021 - October\r\n2024)\r\nProject Manager at Apex Environmental Consultants\r\nLimited (November 2024 to Present)', 'After three years of valuable experience as a Project Engineer, where I was actively involved in project planning, documentation, execution, and management, I was entrusted with the administrative management of a petroleum waste management project. This role not only challenged me but also exposed me to a critical aspect of the oil and gas industry that sparked a profound interest. Through this experience, I recognized the importance of effective petroleum waste management in ensuring sustainable operations and environmental protection. I am therefore eager to deepen my knowledge and expertise in this field through a Masterâ€™s degree in Petroleum Waste Management, with the aim of building my capacity to contribute meaningfully to my career development and the advancement of the industry at large.', 'uploads/students_applications/app_file_68df02cd0ff270.98806319.pdf', '$2y$10$OZTvTiiJCQqPo7FQ8gHZi.QERqZMJk.hPNr3ixW0xvQl/t3x3F5AC', '', 0.00, 'uploads/proof_of_payments/payment_proof_68df02cd102909.80130788.png', 'admitted', 'not suspended', 'RFU/2025/9398', '2025-10-02 22:55:09', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(35, 'enaworedavid@gmail.com', 'enaworedavid@cwmsrfupre.com.ng', 'enaworedavid@gmail.com', '08026757591', '8 Ogbovwan Avenue off Hospital road Ekpan ', '8', 'Bachelor\'s of Science Degree in Microbiology ', 'Supervisor for Environment Uvwie LGA ', 'I want to acquire more formal and professional education around environmental health management so that I can serve the people well and also upgrade my academic qualifications ', 'uploads/students_applications/app_file_68d9a6cfb3f135.92120797.pdf', '$2y$10$LH1XaIvVoTWkuLKSSr9qS.BrSs4qpD8iDYteM0glKSPznOsQzSbKm', '', 0.00, 'uploads/proof_of_payments/payment_proof_68d9a6cfc41d09.19025068.jpg', 'admitted', 'not suspended', 'RFU/2025/2265', '2025-09-28 21:21:19', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(37, 'Sodiq Adedamola Alaka', 'alakasodiq@cwmsrfupre.com.ng', 'alakasodiq@gmail.com', '08034560710', '11 Elderfield Road Bolton', '14', 'Master of Research', 'Senior Permitting Officer, Environment Agency, UK\r\nFebruary 2025 â€“ Present\r\n\r\nReview and determine environmental permits for chemical and hazardous waste treatment facilities under the Environmental Permitting Regulations 2016.\r\n\r\nAssess compliance with Best Available Techniques (BAT) conclusions and appropriate measures for waste management and disposal.\r\n\r\nProvide regulatory advice on waste treatment operations, pollution control, and emissions monitoring.\r\n\r\nContribute to national permitting policies and improvement programmes ensuring environmental protection and resource efficiency.\r\n\r\nMarine Modelling Specialist, Environment Agency, UK\r\n2023 â€“ 2025\r\n\r\nDelivered technical assessments for water quality permits including desalination discharges, applying models such as CORMIX to evaluate salinity, heavy metals, and chemical pollutants.\r\n\r\nSupported Pollution Risk Forecasting (PRF) for bathing waters, integrating rainfall, UV, and hydrodynamic data into predictive models.\r\n\r\nCollaborated with national teams on the Nutrient and Chemical Investigations Programme (CIP), supporting PR24 planning for water companies.\r\n\r\nReviewed H1 surface water risk assessments for large infrastructure projects, identifying errors in pollutant screening and modelling assumptions.\r\n\r\nEnvironmental Consultant, Lee Digital Consults, Nigeria\r\n2018 â€“ 2022\r\n\r\nLed environmental impact assessments (EIA) and developed waste management plans for industrial and infrastructure projects.\r\n\r\nDesigned carbon management strategies, including waste-to-energy feasibility studies, for clients in oil and gas and urban development.\r\n\r\nConducted solid waste audits, landfill assessments, and compliance reviews in line with Nigerian environmental standards.\r\n\r\nSupervised project teams and engaged with regulators and local communities on waste and sustainability issues.', 'I am applying for a PhD in Waste Management at the Centre for Waste Management and Sustainable Resources (CWMSR). My academic and professional journey has given me both technical expertise and practical experience in waste regulation, environmental permitting, and sustainable resource management, and I am committed to advancing research that addresses global waste and sustainability challenges.\r\n\r\nI hold an MRes in Environmental Management from the University of Bolton, where my research focused on the assessment of municipal solid waste management practices in Oyo State, Nigeria. This work strengthened my understanding of waste generation patterns, collection systems, and disposal challenges in rapidly growing urban areas. It also highlighted the importance of integrating policy, technology, and community engagement in building effective waste management systems.\r\n\r\nCurrently, I work as a Senior Permitting Officer with the Environment Agency in the UK. In this role, I review and determine environmental permits for hazardous and chemical waste treatment facilities under the Environmental Permitting Regulations 2016. I ensure compliance with Best Available Techniques (BAT), assess environmental risks, and provide guidance to operators on pollution prevention and resource efficiency. This regulatory experience has given me a detailed understanding of how waste management decisions impact both environmental protection and sustainable development.\r\n\r\nPreviously, I worked as a Marine Modelling Specialist with the Environment Agency, where I contributed to projects on pollution risk forecasting, water quality modelling, and the assessment of industrial discharges. I also supported the Nutrient and Chemical Investigations Programme (CIP) as part of PR24 planning, which required analysing chemical loads and evaluating strategies to reduce nutrient and waste impacts in estuarine and coastal environments.\r\n\r\nBefore joining the Environment Agency, I worked in Nigeria as an Environmental Consultant with Lee Digital Consults, leading environmental impact assessments, carbon management projects, and the development of solid waste management plans for industrial and infrastructure projects. These experiences, together with my academic research, have reinforced my interest in exploring how waste can be managed more sustainably, particularly in contexts where regulatory systems and infrastructure are under pressure.\r\n\r\nThe Centre for Waste Management and Sustainable Resources offers an ideal environment for me to develop this research further. I am particularly interested in investigating integrated approaches to hazardous and municipal waste management that combine regulation, technology, and circular economy principles. My goal is to generate practical solutions that reduce environmental risks, improve compliance with regulatory frameworks, and contribute to global sustainability goals.\r\n\r\nI believe my combination of academic research, regulatory expertise, and professional experience equips me to make a meaningful contribution to the Centreâ€™s research community. Pursuing a PhD at CWMSR will also allow me to strengthen the link between policy and practice in waste management and to provide knowledge that can guide both UK and international efforts toward sustainable resource use.', 'uploads/students_applications/app_file_68dfdb76911d95.91331602.pdf', '$2y$10$zcxrbHv71Scla8wV50F8GORV2nGqMn/vuPjefyhSuA0RnweYtQOoi', '', 0.00, 'uploads/proof_of_payments/payment_proof_68dfdb7694fa22.15834881.PNG', 'admitted', 'not suspended', 'RFU/2025/8437', '2025-10-03 14:19:34', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(38, 'JEVI AJEMOVI EDUZUKA', 'jevieduzuka@cwmsrfupre.com.ng', 'jevieduzuka@hotmail.com', '08037249222', 'KOTOKOTO LAYOUT, OFF ORHUWORUN ROAD, OVWIAN, UDU LGA, WARRI, DELTA STATE, NIGERIA', '14', 'MASTERS IN ENVIRONMENTAL POLICY AND REGULATIONS', 'Sept 2009 to date - CEO, Jaydee Ventures: Waste Management Services, Warri, Delta State.\r\nJan 2007 â€“ Sept 2009 - Materials Manager, Granite Services International Inc, Port Harcourt, Rivers State.\r\nMarch 2000 â€“ Aug 2006:	Head, Materials Dept,  ARCO PETROCHEMICAL ENGINEERING COMPANY LTD, Warri.\r\nApril 1990 â€“ June 1998	Assistant Manager /Manager, Warehousing Services â€“ SGS Inspection Services Nig. Ltd, Lagos:  and Branch Manager/ Senior Executive Manager â€“ SGS Inspection Services Nig. Ltd, Kano Branch.\r\n', 'Driven by the desire for a clean and green environment, and a sustainable earth, I established a Waste Management firm in Warri in September 2009, with the ultimate intention of providing a full gamut of waste management services from cradle to grave. We have operated in Udu LGA, Warri, Delta State as one of the PSPs involved in waste collection and disposal under the SEEFOR programme and the government. We presently have a  Waste Truck, Workers, and Dumpsite (Not Functional). ', 'uploads/students_applications/app_file_68ee2cbd37c666.32422264.pdf', '$2y$10$IELRQ04DshLcbWz4Fka0WOD0Uxv3UpH7MyIriSsyY1oaH81YtbE.S', '', 0.00, 'uploads/proof_of_payments/payment_proof_68ee2cbebb5214.79341420.png', 'admitted', 'not suspended', 'RFU/2025/8987', '2025-10-14 10:58:06', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(39, 'Centurion Okon Awakessien', 'centurionawakessien@cwmsrfupre.com.ng', 'centurionawakessien@gmail.com', '08123720701', 'stone house ogbomro delta state.', '7', 'Bachelor of social science', 'Music Instructor\r\nInternship at CMADI\r\n', 'My Personal Statement\r\n\r\nMy conviction that real progress requires bringing social justice and responsibility for the environment together continually inspires my pursuits in both academia and work. An integrated solution which brings together technical expertise with significant public involvement is necessary due to the interconnectedness of ecological deterioration, inefficient waste systems, and community misery. This belief becomes the base of my application to the Centre for Waste Management and Sustainable Resources\' Master of Environmental Social Work and Community Development program.\r\n\r\nI obtained my political science undergraduate degree from the National Open University of Nigeria, where I also gained a solid knowledge of societal dynamics, governance, and policy frameworks. I grew more conscious of how inequality in society obstruct sustainable development during my studies, especially in marginalized groups. A increasing interest in social work and environmental sustainability was ignited by this discovery, and it has since developed into a professional goal. I made a conscious choice to connect policy knowledge with workable solutions that uplift communities and save the environment by choosing to pursue this Master\'s program.\r\n\r\nI\'m currently working with CMADI as a Sustainable Development Goals SDG Intern, contributing to projects that support the UN 2030 Agenda. Supporting outreach initiatives, contributing to sustainable practice research, and assisting in the facilitation of educational programs centered on waste reduction and environmental awareness are all part of my job. Being able to apply sustainable development principles to local contexts has improved as a result of this experience, which has given me the opportunity to interact directly with a range of individuals, including organizations and local inhabitants. My knowledge of how environmental concerns disproportionately affect underprivileged populations is growing as a result of the internship, which also helps me refine my abilities in program management, community engagement, and impact assessment.\r\n\r\nIn addition to this, my work as a music instructor has offered valuable insights into education, empowerment, and social development. Teaching music has required me to be flexible, empathetic, and creative, tailoring lessons to suit learners of varying ages and backgrounds. More than just technical instruction, I have seen how music fosters resilience, builds self-esteem, and promotes unity. These experiences have reinforced my belief that sustainable development must also nurture the cultural and emotional wellbeing of communities.\r\nThe Centre for Waste Management and Sustainable Resources provide the perfect learning environment for combining these experiences into an appropriate professional path. I am especially interested in the program\'s interdisciplinary structure, which unites social work, policy, and environmental science. The curriculum and hands-on training are certain to give me the skills I need to create inclusive, successful, and long-lasting actions. \r\n\r\nLeading projects that enable communities to responsibly manage garbage while promoting social fairness is my long-term objective. By working at the convergence of community engagement, education, and policy, I hope to make sure that no group is left behind in the fight for sustainability. I will graduate from this Master\'s program as a practitioner with the ability to create durable, welcoming environments and propel positive change.', NULL, '$2y$10$HSLggIfhZwi4s48OWPYABedkv22dbjzJkBuNgdFr/NQN1HRnpyfxW', '', 0.00, 'uploads/proof_of_payments/payment_proof_68eecdcf03b064.51400243.jpg', 'admitted', 'not suspended', 'RFU/2025/5739', '2025-10-14 22:25:19', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(40, 'OLAWE OLAOLUWA OLANIYI', '', 'laoluolawe@gmail.com', '08063474367', '15, Tunde Williams Street By School Bus Junction, Asaba, Delta State', '14', 'MSc Degree', 'Starich Recycling Technology Co. Ltd [Director of Operations] Contract Onitsha, Anambra State. \r\n2023 â€“ Present \r\nâ€¢ Ensure quality & production goals are met in an efficient manner by  managing the processing of inbound, stored and outbound materials.  \r\nâ€¢ Verify recyclable products and processed materials meet established specifications prior to shipping.\r\n\r\nWaste Box [Executive Director] South Region, Nigeria. \r\n2021 â€“ Present \r\nâ€¢ Implement strategic plans by working with senior stakeholders. \r\nâ€¢ Evaluate and track the success of the company in reaching its goals. \r\n ', 'I have decided to pursue a Phd Waste Management after a good deal of self evaluation. My decision of pursuing this program followed naturally after carefully considering my academic background, the areas of my interest and my ultimate professional experience in Recycling/Waste management.\r\n\r\nEnvironmental issues like Climate change is the most serious issue of the world today. The present environmental situation has intrigued my interest in pursuing waste management, this led me searching for a prestigious institute to horn my skills in waste management analysis and i found Federal University of Petroleum Resources,Effurun, Delta State which is known to be the right amalgamation of learning from field excursions and practical.\r\n\r\nI strongly believe in few values, which are hard work that is necessity to produce results, discipline that is necessity to finish task before deadlines and persistence that is necessity to sail through unproductive periods. My attempt throughout has been to inculcate these qualities in.', NULL, '$2y$10$oULQdsW96oJvRKRXIDzgJ.xjLweK60UmIkfNsWylPZz5vzNEk7hMW', '', 0.00, 'uploads/proof_of_payments/payment_proof_68efc513637090.00513538.jpg', 'applied', 'not suspended', NULL, '2025-10-15 16:00:19', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(41, 'EDWIN ANYIM', 'akachiedwin@cwmsrfupre.com.ng', 'akachiedwin@yahoo.com', '08031883143, 08', '2 sam akpuireme avenue abaranje ikotun lagos', '5', 'MSc Business Administration', 'over 7 years experience as a safety supervisor in the oil and gas, manufacturing, mining industry.', 'I am writing to express my keen interest in pursuing a Master of Science in Petroleum Waste Management. With a strong foundational background in environmental science and a passionate commitment to sustainable development, I am eager to deepen my understanding of this critical field and contribute positively to the management of petroleum-related waste.\r\nMy academic journey began with a bachelorâ€™s degree in petroleum engineering, where I developed a profound appreciation for ecological balance and the importance of responsible resource management. Throughout my undergraduate studies, I engaged in several projects that explored the environmental impacts of various industrial activities, with a specific focus on fossil fuel extraction and processing. This exposure ignited my interest in petroleum waste management a field directly linked to pressing global environmental challenges.\r\nThe urgency of addressing petroleum waste management has never been more critical. With increasing global energy demands and the ongoing transition towards cleaner energy sources, effective waste management strategies will play a pivotal role in reducing environmental degradation. I am particularly drawn to the multidisciplinary approach of this MSc program, which integrates engineering principles, policy analysis, and environmental science. I believe that a comprehensive understanding of these areas will equip me with the skills necessary to navigate the complexities of petroleum waste management.\r\nI am also committed to contributing to the academic community. I plan to engage in research activities focusing on waste minimization techniques and the development of economically viable recycling processes. My goal is to publish findings that can inform industry practices and influence policy decisions, thereby fostering a more sustainable future for the petroleum industry.\r\nIn addition to my academic and professional background, I bring strong analytical skills, attention to detail, and the ability to work collaboratively in team-oriented environments. I am excited about the opportunity to learn from distinguished faculty members and collaborate with fellow students who share my passion for sustainable practices in the petroleum sector.\r\nIn conclusion, pursuing an MSc in Petroleum Waste Management is a crucial step in my career path. I am eager to expand my knowledge and skills in this vital field, and I am confident that your program will provide the foundation I need to make a meaningful contribution to environmental sustainability in the petroleum industry. Thank you for considering my application.\r\n\r\nYours faithfully,  \r\nEdwin Anyim  \r\n\r\n', 'uploads/students_applications/app_file_68f20fe17eef84.30966661.pdf', '$2y$10$CB66lmBe97vMtQi5XTLz2.EzLZzzFg0MUYAzjo6lQ2W25.F7KPHpS', '', 0.00, 'uploads/proof_of_payments/payment_proof_68f20fe1b8f909.28708370.jpg', 'admitted', 'not suspended', 'RFU/2025/2383', '2025-10-17 09:44:01', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(42, 'AKOMAYE PETER BENSON', '', 'jeraw2@gmail.com', '08055512812', 'km 4 Refinery rd,By Mega Hilton Hotel Ekpan- Warri, Delta State', '7', 'PgD WASTE MANAGEMENT-Environmental Management & Toxicology Dept.- Federal  University Of  Petroleum Resources Efurrun (FUPRE) Delta State.', 'Entrepreneurship and Enterprise management- SEF 2019  Oxford SBS-UK                                                   \r\n2019 \r\nï‚· Fields operations Mgr / Project Supervisor ï‚®  Environmental Services-B2 Oil & Gas Projects Ltd    2009 - 2016 \r\nï‚· Lab. Analyst / Microbiologist ï‚®Global Environmental Consultants Ltd, Forcados operations  \r\n2008- 2018 \r\nï‚· Environmental Scientist /P Consultant/ Sewage &Wastewater Innovations.ï‚® Jaymak Energy Ltd, Nig2012 - Date \r\nï‚·  Science Teacher/ Biologyï‚®NYSC-Onicha Ugbo Girls Secondary School, Delta State. \r\nï‚· Laboratory Trainee /IT Studentâ€”Cross River Basin Dev. Authority(Federal min. Of Water res.) Calabar .           \r\n2007 â€“ 2008 \r\n2004', '\r\n\r\nMy interest in environmental and social development stems from an experience while supervising a sewage treatment project in Warri, where I observed firsthand the adverse effects of polluted water on community health. That incident shaped my conviction that environmental issues extend beyond science and technologyâ€”they are deeply social, influencing livelihoods and human dignity.\r\n\r\nAs an Environmental Scientist with over a decade of experience in the oil and gas sector, I have contributed to environmental compliance monitoring, wastewater management, and post-impact assessments for organizations such as SPDC, Chevron, and GEC Nigeria Ltd. These experiences have strengthened my appreciation of the link between sustainable environmental management and social welfare.\r\n\r\nWith a B.Sc. in Microbiology and a Postgraduate Diploma in Waste Management from FUPRE, I seek to advance my knowledge through the MSc in **Environmental Social Work and Development** at **CWMR, FUPRE**. The programme aligns with my professional goal of integrating social work principles into environmental practice, particularly in the areas of community engagement, environmental justice, and sustainable development.\r\n\r\nI am confident that this programme will equip me with the theoretical and practical tools needed to design interventions that protect the environment while improving the quality of life in affected communities.\r\n', 'uploads/students_applications/app_file_68f3632ae292f6.77798813.pdf', '$2y$10$oWSgJYQ52iRrGBrkur87lu4DSol1RU7kNDR4T4ls6ywqMf6MMNpPu', '', 0.00, 'uploads/proof_of_payments/payment_proof_68f3632b3ea7e7.05250981.jpg', 'applied', 'not suspended', NULL, '2025-10-18 09:51:39', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(43, 'IMELDA BLANKSON', 'imeldablankson4u@cwmsrfupre.com.ng', 'imeldablankson4u@gmail.com', '+2348035313687', '10 CIRCULAR ROAD, ELEKAHIA HOUSING ESTATE, PORT HARCOURT, NIGERIA', '14', 'MASTERS', 'Over 15 years in supervisory and managerial position managing HSE across different sectors and industries.', 'My academic foundation in Sustainable Waste Management has provided a strong platform for integrating environmental science with social responsibility. Through research and applied projects, I have examined the intersection of Extended Producer Responsibility (EPR), circular resource loops, and value stream optimization as tools for environmental transformation. These studies reinforced my conviction that true sustainability requires more than efficient disposal systemsâ€”it demands community engagement, data-driven innovation, and policies that reshape production and consumption at their roots.\r\n\r\nParallel to my academic growth, my professional experience has nurtured an intimate understanding of how environmental neglect amplifies human vulnerability. Working in different sectors has taught me that waste management is not only an environmental issue but also a social one. Each improperly handled material, each inefficient system, has human consequences. This understanding pushes me to explore waste not merely as a technical problem but as a human systems challenge requiring equity-driven innovation.\r\n\r\nThe research ethos of CWMS, FUPRE, focused on advancing indigenous solutions to waste, energy, and resource management, resonates with my goal to bridge academic theory with actionable policy and practice. I am particularly interested in studying integrated municipal waste systems and circular economy transitions in urban African contexts, where population growth and consumption pressures demand scalable, inclusive models. \r\nMy vision is to contribute to the development of frameworks that align government regulations, private sector responsibility, and community participation into a unified sustainability ecosystem.\r\n\r\nLooking forward, I see my PhD journey not as an academic destination but as a launchpad for transformative environmental leadership. My ambition is to lead multidisciplinary projects that close the loop between waste generation, resource recovery, and public healthâ€”ultimately shaping communities that view waste as a resource rather than a residue. \r\n\r\nThrough research collaboration, policy advocacy, and technological integration, I hope to strengthen Africaâ€™s role in the global sustainability movement.\r\n\r\nIn every step of my professional and academic journey, I have embraced the belief that sustainable progress begins where people and the planet meet. \r\nCWMS, FUPRE provides the environment, mentorship, and research infrastructure to actualize this vision. With a deep sense of purpose and preparation, I am ready to contribute to groundbreaking research and to the creation of resilient waste systems that will define the environmental future of our world.', NULL, '$2y$10$muIjkROABd4x7GtlAXVyBORo93FRO67qEVD0/F26j4p3J4Cx9165K', '', 0.00, 'uploads/proof_of_payments/payment_proof_68f647046d0d14.93920225.jpeg', 'admitted', 'not suspended', 'RFU/2025/9171', '2025-10-20 14:28:20', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(44, 'OLAOLUWA OLAWE', 'olawe_laozy@cwmsrfupre.com.ng', 'olawe_laozy@yahoo.com', '08063474367', '10, Seun Nwachi Street, Isheri, Lagos', '14', 'M.Sc', 'Starich Recycling Technology Co. Ltd [Director of Operations] Contract\r\nOnitsha, Anambra State. (2023- Present)\r\nWaste Box [Executive Director]\r\nSouth Region, Nigeria. (2021-Present)\r\n', 'I have decided to pursue a Phd Waste Management after a good deal of self evaluation. My decision of pursuing this program followed naturally after carefully considering my academic background, the areas of my interest and my ultimate professional experience in Recycling/Waste management.\r\n\r\nEnvironmental issues like Climate change is the most serious issue of the world today. The present environmental situation has intrigued my interest in pursuing waste management, this led me searching for a prestigious institute to horn my skills in waste management analysis and i found Federal University of Petroleum Resources,Effurun, Delta State which is known to be the right amalgamation of learning from field excursions and practical.\r\n\r\nI strongly believe in few values, which are hard work that is necessity to produce results, discipline that is necessity to finish task before deadlines and persistence that is necessity to sail through unproductive periods. My attempt throughout has been to inculcate these qualities in.', NULL, '$2y$10$aNoWRuzA7o2QMyqRlXF5puuQo/E3dYX9qRiDViSw40Lti1aLLZBbO', '', 0.00, 'uploads/proof_of_payments/payment_proof_68f8bd0ce9c859.05353728.jpg', 'admitted', 'not suspended', 'RFU/2025/8322', '2025-10-22 11:16:29', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(45, 'ENENMOH, Lawrence Ebialim', 'ichristopher75@cwmsrfupre.com.ng', 'ichristopher75@yahoo.com', '07032972498', '298, Cadastral Zone, Durumi, Abuja. Nigeria', '6', 'BSc', 'Demonstrated progressively responsible leadership qualities culminating in leadership/ supervising of the Agencyâ€™s activities in various places of postings. These were the Oando depots, Total, Oando Total Joint venture, all in Lagos and the NNPC depot in Ibadan and the NNPC regional office in Lagos. In other words, career has spanned through the South western region and the North central regions.', 'I am applying for the Safety Program in Waste Management because of my strong interest in environmental protection and public health. My research on â€œAssessment of Healthcare Waste Management Practices in Warri and Environsâ€ exposed me to the risks of poor waste handling and the importance of safety in waste operations. This experience inspired me to pursue further training to improve my understanding of safe and sustainable waste management practices.', 'uploads/students_applications/app_file_6901a900890537.46811813.pdf', '$2y$10$WlFSCZwukCnnBTLeD0gyB.uqMHnqGNaxDDDSb7I7M6ScYF6XUdkX6', '', 0.00, 'uploads/proof_of_payments/payment_proof_6901a901e894f0.23315425.jpg', 'admitted', 'not suspended', 'RFU/2025/1637', '2025-10-29 05:41:22', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(49, 'Agadagba Joan', '', 'edirinjoan@gmail.com', '08135951583', '1 Omafuaire Close, Olughor Layout. Ogbumoro. Effurun', '14', 'Maters', 'So many', 'Nil', 'uploads/students_applications/app_file_692937b225c4f9.38769536.pdf', '$2y$10$Cx7.RWGeG5kiQmSrM2e8IefElW3D0cbpwl7r/7pTJb8p7ewskItbG', '', 0.00, 'uploads/proof_of_payments/payment_proof_692937b3316eb0.06521586.jpeg', 'applied', 'not suspended', NULL, '2025-11-28 05:48:36', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(46, 'Nwokafor chukwunyere venantius', 'chuksvenantius@cwmsrfupre.com.ng', 'chuksvenantius@yahoo.com', '08037868015', 'House 7 D close CBS great estate lugbe Abuja', '7', 'HND  architecture with distinction', 'Over 20 years work experience with reputable organization. ', 'I strongly believe that I have all it takes to run this program which will in turn help me achieve my dream of participating in community development', 'uploads/students_applications/app_file_6904938dc9e142.17950723.pdf', '$2y$10$cVwqEpEi7FthuFQR6g1anODiE0CXJH2ojwVjuheWAzJ6adPz.sbA.', '', 0.00, 'uploads/proof_of_payments/payment_proof_6904938dccb239.40517037.jpg', 'admitted', 'not suspended', 'RFU/2025/6597', '2025-10-31 10:46:38', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(47, 'Dr Akinyemi ogunkeyede', 'ogunkeyedeakinyemi@cwmsrfupre.com.ng', 'ogunkeyedeakinyemi@gmail.com', '09030223041', 'Centre For Waste Management And Sustainable Resources, Fupre', '6', 'B.Sc.', 'zxsdv cevexas', 'c ggsacwdawcf3a', 'uploads/students_applications/app_file_691b7619ad76f3.87449875.pdf', '$2y$10$hB89kajnwGeXmM/VE8ZU9OGnM7MZuGdtsaUA8L6zAg3QlFucwT2ei', '', 0.00, 'uploads/proof_of_payments/payment_proof_691b761a1ae0d9.15891628.jpg', 'admitted', 'not suspended', 'RFU/2025/0532', '2025-11-17 19:23:06', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(48, 'Matilda Iwunor', 'mkiwunor@cwmsrfupre.com.ng', 'mkiwunor@gmail.com', '+491630045932', '12B, ADEGBENLE STREET, CHEVVY VIEW ESTATE, LEKKI, LAGOS, NIGERIA.', '15', 'MSc', 'I volunteered as a community worker in Pitakwa, Rivers State after my MSc.', 'Hailing from Southern Nigeria, I have been intrigued by the intricate relationship between our environment and our communities: how the environment and its resources sustain us and contribute immensely to our source of livelihood.\r\n\r\nThis led me to pursue a Bachelorâ€™s degree in Industrial Chemistry and a Masterâ€™s in Environmental Assessment and Management, and as I seek to take the next step in my career, I hereby apply for the PhD program in Environmental Social Work and Community Development.\r\n\r\nDuring my undergraduate studies, I not only delved into chemical processes but also began to understand how industrial practices can impact the world around us.\r\n\r\nI visited communities during a project about sustainable practices in the aviation industry and it opened my eyes to the pressing need for solutions that address both environmental and social issues. This realization laid the groundwork for my masterâ€™s thesis, where I investigated the effects of the aviation industry on neighbouring communities, which revealed the disparities that exist in our society.\r\n\r\nWhile pursuing my MSc, I had the opportunity to engage with communities directly, which was rewarding.Â \r\n\r\nIn addition, I worked on a project examining water quality in water bodies (close to residential areas), which are mainly for domesticÂ use. I discussed with local residents and hearing their stories motivated me to advocate for those whose voices are often overlooked. It became clear to me that effective solutions require not just scientific expertise, but also a good understanding of the community\'s needs.\r\n\r\nIÂ  believe that real change happens at the grassroots level, where community members have the power to shape their environmental futures. Itâ€™s inspiring to see how collective effort can empower people and foster sustainable practices.\r\n\r\nThis PhD program resonates deeply with my goals. I am particularly drawn to your interdisciplinary approach, which I believe is crucial for addressing the complexities of environmental challenges.\r\n\r\nI am eager to learn and to engage in research that explores participatory frameworks, ensuring that community perspectives are at the heart of environmental solutions.\r\n\r\nI aspire to work with NGOs or within governmental organizations to promote policies that empower communities.\r\n\r\nIn pursuing this PhD, I hope to gain the skills and insights necessary to lead initiatives that prioritize both ecological health and social justice.\r\n\r\nIn conclusion, I am excited about the path that lies ahead and the opportunity to contribute to the field of Environmental Social Work and Community Development. I am committed to making a meaningful difference, and I believe that my journey has uniquely prepared me for this endeavor.Â \r\n\r\nThank you for considering my application.', 'uploads/students_applications/app_file_691da85515b314.30155201.pdf', '$2y$10$CFnRQJ.tu.4O0ApjWQBLbOBLSnbDX7KC/tJ6ZaiRAkoGN97uU1vfG', '', 0.00, 'uploads/proof_of_payments/payment_proof_691da8567061a4.31346762.jpg', 'admitted', 'not suspended', 'RFU/2025/8417', '2025-11-19 11:21:58', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current'),
(50, 'OGUORI-OKODASO Ejiroghene', '', 'okodaso.ejiro@gmail.com', '08159757831', 'No. 107 Orhuwhorun Road, Ekete   ', '14', 'M.Sc ', 'About 20years of service as an Environmental Health Officer with the Delta State Waste Management Board. ', 'Sustainable Waste Management: a result of continuous improvement in proper waste management procedures and policies.  ', NULL, '$2y$10$0uKgmWTb9sVadD9hrxsfnuxLlmOD0WoES3dSDrsN4zhvEr/AJBKgi', '', 0.00, 'uploads/proof_of_payments/payment_proof_697244de9b2e26.52173542.jpg', 'applied', 'not suspended', NULL, '2026-01-22 15:40:15', '{\"level_id\": 1, \"semester_id\": 1}', '[\r\n  {\"level_id\":1,\"semester_id\":1},\r\n  {\"level_id\":1,\"semester_id\":2},\r\n  {\"level_id\":2,\"semester_id\":1},\r\n  {\"level_id\":2,\"semester_id\":2},\r\n  {\"level_id\":3,\"semester_id\":1},\r\n  {\"level_id\":3,\"semester_id\":2},\r\n  {\"level_id\":4,\"semester_id\":1},\r\n  {\"level_id\":4,\"semester_id\":2},\r\n  {\"level_id\":5,\"semester_id\":1},\r\n  {\"level_id\":5,\"semester_id\":2}\r\n]', 'current');
