(104, 'Nwokafor chukwunyere venantius', 'chuksvenantius@cwmsrfupre.com.ng', 'chuksvenantius@yahoo.com', '08037868015', 'House 7 D close CBS great estate lugbe Abuja', '7', 'HND  architecture with distinction', 'Over 20 years work experience with reputable organization. ', 'I strongly believe that I have all it takes to run this program which will in turn help me achieve my dream of participating in community development', 'uploads/students_applications/app_file_6904938dc9e142.17950723.pdf', '$2y$10$cVwqEpEi7FthuFQR6g1anODiE0CXJH2ojwVjuheWAzJ6adPz.sbA.', '', 0.00, 'uploads/proof_of_payments/payment_proof_6904938dccb239.40517037.jpg', 'admitted', 'not suspended', 'RFU/2025/6597', '2026-01-28 15:35:39', '{\"level_id\":2,\"semester_id\":2}', '[{\"level_id\": 1, \"semester_id\": 1},{\"level_id\": 1, \"semester_id\": 2},{\"level_id\": 2, \"semester_id\": 1},{\"level_id\": 2, \"semester_id\": 2},{\"level_id\": 3, \"semester_id\": 1},{\"level_id\": 3, \"semester_id\": 2},{\"level_id\": 4, \"semester_id\": 1},{\"level_id\": 4, \"semester_id\": 2}]', 'L2S2'),
(105, 'Dr Akinyemi ogunkeyede', 'ogunkeyedeakinyemi@cwmsrfupre.com.ng', 'ogunkeyedeakinyemi@gmail.com', '09030223041', 'Centre For Waste Management And Sustainable Resources, Fupre', '6', 'B.Sc.', 'zxsdv cevexas', 'c ggsacwdawcf3a', 'uploads/students_applications/app_file_691b7619ad76f3.87449875.pdf', '$2y$10$hB89kajnwGeXmM/VE8ZU9OGnM7MZuGdtsaUA8L6zAg3QlFucwT2ei', '', 0.00, 'uploads/proof_of_payments/payment_proof_691b761a1ae0d9.15891628.jpg', 'admitted', 'not suspended', 'RFU/2025/0532', '2026-01-28 15:35:39', '{\"level_id\":2,\"semester_id\":2}', '[{\"level_id\": 1, \"semester_id\": 1},{\"level_id\": 1, \"semester_id\": 2},{\"level_id\": 2, \"semester_id\": 1},{\"level_id\": 2, \"semester_id\": 2},{\"level_id\": 3, \"semester_id\": 1},{\"level_id\": 3, \"semester_id\": 2},{\"level_id\": 4, \"semester_id\": 1},{\"level_id\": 4, \"semester_id\": 2}]', 'L2S2'),
(106, 'Matilda Iwunor', 'mkiwunor@cwmsrfupre.com.ng', 'mkiwunor@gmail.com', '+491630045932', '12B, ADEGBENLE STREET, CHEVVY VIEW ESTATE, LEKKI, LAGOS, NIGERIA.', '15', 'MSc', 'I volunteered as a community worker in Pitakwa, Rivers State after my MSc.', 'Hailing from Southern Nigeria, I have been intrigued by the intricate relationship between our environment and our communities: how the environment and its resources sustain us and contribute immensely to our source of livelihood.\r\n\r\nThis led me to pursue a Bachelorâ€™s degree in Industrial Chemistry and a Masterâ€™s in Environmental Assessment and Management, and as I seek to take the next step in my career, I hereby apply for the PhD program in Environmental Social Work and Community Development.\r\n\r\nDuring my undergraduate studies, I not only delved into chemical processes but also began to understand how industrial practices can impact the world around us.\r\n\r\nI visited communities during a project about sustainable practices in the aviation industry and it opened my eyes to the pressing need for solutions that address both environmental and social issues. This realization laid the groundwork for my masterâ€™s thesis, where I investigated the effects of the aviation industry on neighbouring communities, which revealed the disparities that exist in our society.\r\n\r\nWhile pursuing my MSc, I had the opportunity to engage with communities directly, which was rewarding.Â \r\n\r\nIn addition, I worked on a project examining water quality in water bodies (close to residential areas), which are mainly for domesticÂ use. I discussed with local residents and hearing their stories motivated me to advocate for those whose voices are often overlooked. It became clear to me that effective solutions require not just scientific expertise, but also a good understanding of the community\'s needs.\r\n\r\nIÂ  believe that real change happens at the grassroots level, where community members have the power to shape their environmental futures. Itâ€™s inspiring to see how collective effort can empower people and foster sustainable practices.\r\n\r\nThis PhD program resonates deeply with my goals. I am particularly drawn to your interdisciplinary approach, which I believe is crucial for addressing the complexities of environmental challenges.\r\n\r\nI am eager to learn and to engage in research that explores participatory frameworks, ensuring that community perspectives are at the heart of environmental solutions.\r\n\r\nI aspire to work with NGOs or within governmental organizations to promote policies that empower communities.\r\n\r\nIn pursuing this PhD, I hope to gain the skills and insights necessary to lead initiatives that prioritize both ecological health and social justice.\r\n\r\nIn conclusion, I am excited about the path that lies ahead and the opportunity to contribute to the field of Environmental Social Work and Community Development. I am committed to making a meaningful difference, and I believe that my journey has uniquely prepared me for this endeavor.Â \r\n\r\nThank you for considering my application.', 'uploads/students_applications/app_file_691da85515b314.30155201.pdf', '$2y$10$CFnRQJ.tu.4O0ApjWQBLbOBLSnbDX7KC/tJ6ZaiRAkoGN97uU1vfG', '', 0.00, 'uploads/proof_of_payments/payment_proof_691da8567061a4.31346762.jpg', 'admitted', 'not suspended', 'RFU/2025/8417', '2026-01-28 15:35:39', '{\"level_id\":2,\"semester_id\":2}', '[{\"level_id\": 1, \"semester_id\": 1},{\"level_id\": 1, \"semester_id\": 2},{\"level_id\": 2, \"semester_id\": 1},{\"level_id\": 2, \"semester_id\": 2},{\"level_id\": 3, \"semester_id\": 1},{\"level_id\": 3, \"semester_id\": 2},{\"level_id\": 4, \"semester_id\": 1},{\"level_id\": 4, \"semester_id\": 2}]', 'L2S2'),
(107, 'OGUORI-OKODASO Ejiroghene', '', 'okodaso.ejiro@gmail.com', '08159757831', 'No. 107 Orhuwhorun Road, Ekete   ', '14', 'M.Sc ', 'About 20years of service as an Environmental Health Officer with the Delta State Waste Management Board. ', 'Sustainable Waste Management: a result of continuous improvement in proper waste management procedures and policies.  ', NULL, '$2y$10$0uKgmWTb9sVadD9hrxsfnuxLlmOD0WoES3dSDrsN4zhvEr/AJBKgi', '', 0.00, 'uploads/proof_of_payments/payment_proof_697244de9b2e26.52173542.jpg', 'applied', 'not suspended', NULL, '2026-01-28 15:35:39', '{\"level_id\":2,\"semester_id\":2}', '[{\"level_id\": 1, \"semester_id\": 1},{\"level_id\": 1, \"semester_id\": 2},{\"level_id\": 2, \"semester_id\": 1},{\"level_id\": 2, \"semester_id\": 2},{\"level_id\": 3, \"semester_id\": 1},{\"level_id\": 3, \"semester_id\": 2},{\"level_id\": 4, \"semester_id\": 1},{\"level_id\": 4, \"semester_id\": 2}]', 'L2S2'),
